def _extract_child_elements(parent_element) -> list:
    """
    Extract child elements from an XML element into a list of dictionaries.
    
    Args:
        parent_element: An lxml Element.
        
    Returns:
        List of dicts with 'tag', 'namespace', 'localname', 'text', 
        'attributes', and 'children' keys.
    """
    elements = []
    for child in parent_element:
        if not isinstance(child.tag, str):
            # Skip comments, processing instructions, etc.
            continue
            
        qname = etree.QName(child.tag)
        element_info = {
            'tag': child.tag,
            'namespace': qname.namespace,
            'localname': qname.localname,
            'text': child.text.strip() if child.text and child.text.strip() else None,
            'attributes': dict(child.attrib),
            'children': _extract_child_elements(child),
        }
        elements.append(element_info)
    
    return elements


def create_soap_response(body_content: str, soap_version: str = 'soap11') -> str:
    """
    Create a SOAP response envelope.
    
    Args:
        body_content: XML string to place inside the SOAP Body.
        soap_version: 'soap11' or 'soap12'.
        
    Returns:
        A SOAP XML response string.
    """
    soap_namespaces = {
        'soap11': 'http://schemas.xmlsoap.org/soap/envelope/',
        'soap12': 'http://www.w3.org/2003/05/soap-envelope',
    }
    
    ns = soap_namespaces.get(soap_version, soap_namespaces['soap11'])
    nsmap = {'soap': ns}
    
    envelope = etree.Element(etree.QName(ns, 'Envelope'), nsmap=nsmap)
    body = etree.SubElement(envelope, etree.QName(ns, 'Body'))
    
    if body_content:
        # Parse body content securely
        parser = etree.XMLParser(
            resolve_entities=False,
            no_network=True,
            huge_tree=False,
        )
        try:
            body_element = etree.fromstring(body_content.encode('utf-8'), parser)
            body.append(body_element)
        except etree.XMLSyntaxError:
            # If not valid XML, add as text
            body.text = body_content
    
    return etree.tostring(
        envelope,
        xml_declaration=True,
        encoding='UTF-8',
        pretty_print=True
    ).decode('utf-8')


